create table dirkspzm32.isi_liefs (
    sid                    varchar2(2 char) default '01' not null enable,
    firma_nr               number(6, 0) default 1 not null enable,
    vorgang_typ            varchar2(3 char) default 'WAE' not null enable,
    vorgang_id             number(*, 0),
    vorgang_pos            number(*, 0),
    adress_nr              number(*, 5),
    adress_id              number(*, 0),
    order_adress_id        number(*, 0),
    li_nr                  number(*, 5) not null enable,
    li_pos_nr              number(*, 0) not null enable,
    auftrag                number(*, 5),
    pos_nr                 number(*, 0),
    upos_nr                number(*, 0),
    lam_bh_id              number(*, 0) not null enable,
    lam_id                 number(*, 0) not null enable,
    lte_id                 varchar2(20 char),
    lhm_id                 varchar2(20 char),
    artikel_id             number(*, 0),
    login_id               number(*, 0),
    charge_id              number(*, 0),
    serie_id               number(*, 0),
    menge                  number(*, 3),
    liefs_datum            date,
    res_id                 number(*, 0),
    uebergabe_temp         number(*, 5),
    fahrzeug_ankunft       varchar2(20 char),
    fahrzeug_abfahrt       varchar2(20 char),
    fahrzeug_kennz         varchar2(20 char),
    transporteur           varchar2(30 char),
    be_nr                  number(*, 5),
    lte_name               varchar2(22 char) not null enable,
    menge_basis            varchar2(3 char) not null enable,
    mengeneinheit_basis    varchar2(10 char) not null enable,
    lam_mhd                date,
    v_lhm_id               varchar2(19 char),
    inaktiv_grund          number(*, 5),
    login_id_verantwortung number(*, 0),
    info_text              varchar2(40 char),
    avis_status            varchar2(10 char),
    temperatur_gelesen     number(*, 5),
    zollplombe_id          varchar2(20 char)
);

alter table dirkspzm32.isi_liefs
    add constraint pk_isi_liefs
        primary key ( li_nr,
                      li_pos_nr,
                      lam_bh_id )
            using index enable;


